    +'<span>��ȭ: <b style="color:#4ade80">ȭ�ϡ�</b>=�繰���ο� �� <b style="color:#60a5fa">ȭ�ǡ�</b>=���� �� <b style="color:#c084fc">ȭ����</b>=���� �� <b style="color:#f87171">ȭ���</b>=����</span>'
    +'</div>';

