  var JIHE_RESULT_MAP={��:'earth',��:'earth',��:'wood',��:'wood',��:'fire',��:'fire',��:'metal',�:'metal',��:'water',��:'water',��:'fire',ڱ:'fire'};
  var heTrapFound=false;
