          '<span style="font-size:.78rem;color:#a08040"> &nbsp;|&nbsp; ���� ��ȣ��: '+resonanceNums+'</span>'+
        '</div>'+
        '<div class="lc-games">'+gamesHTML+'</div>'+
        '<div class="lc-reason">'+
          '<div class="lc-reason-title">?? ������ �ٰ� ? �� ��ȣ���� ��Ű� ����ȭ�Ǵ� ����</div>'+
          reasons.map(function(r){return '<div class="lc-reason-item">'+r+'</div>';}).join('')+
        '</div>'+
        '<button id="lottoRedrawBtn" class="lotto-redraw-btn">?? �ٽ� �ζǹ�ȣ �̱� ? ���ο� ���� ������ ����</button>'+
        '<div class="lotto-history-count" id="lottoHistCount"></div>'+
        '<div class="lc-disclaimer">�� �� ��ȣ�� �����С��������� ���� �������� �������� �� �������Դϴ�.<br>�ζǴ� �������� Ȯ���� ���� ���� �������� �����ϼ���. ??</div>'+
      '</div>'+ // end lottoResultArea
    '</div>';

  area.innerHTML=html;
  card.style.display='block';
  syncReportHeightFromNode(card);

  /* �����丮 ī��Ʈ ǥ�� */
